solution_code:
#include <iostream>
#include <vector>

int main()
{
    int n{};
    int threshold{};
    std::cin >> n >> threshold;

    std::vector<int> nums(n);
    for (int i{ 0 }; i < n; ++i)
        std::cin >> nums[i];

    int count{ 0 };
    auto filter{ [threshold, &count](int val)
    {
        if (val > threshold)
        {
            std::cout << val << '\n';
            ++count;
        }
    } };

    for (int val : nums)
        filter(val);

    std::cout << "Count: " << count << '\n';

    return 0;
}
